fn __execute__(ref self: ContractState, calls: Span<Call>) -> Span<Span<felt252>> {
    let mut results: Array<Span<felt252>> = ArrayTrait::new();
    for call in calls {
        if *call.to == starknet::get_contract_address() {
            panic_with_felt252('SESSION_SELF_CALL_BLOCKED');
        }
        let ret = starknet::call_contract_syscall(*call.to, *call.selector, *call.calldata).unwrap_syscall();
        results.append(ret);
    }
    results.span()
}

